import api from './api';

export const getArtistes = () => api.get('/artistes');
export const getArtiste = (id) => api.get(`/artistes/${id}`);
export const createArtiste = (data) => api.post('/artistes', data);
export const updateArtiste = (id, data) => api.put(`/artistes/${id}`, data);
export const deleteArtiste = (id) => api.delete(`/artistes/${id}`);
